      <span className="min-w-0 flex-1 truncate text-left">{children}</span>
      <ArrowUpDown
        className={cn(
          "h-3 w-3 shrink-0 transition-colors",
          sorted ? "text-foreground" : "text-muted-foreground/40",
        )}
